import{_ as l,o as e,c as i,a2 as t}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"2004年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2004年/核心总结.md","filePath":"01_letters/2004年/核心总结.md"}'),o={name:"01_letters/2004年/核心总结.md"};function r(h,a,n,u,d,s){return e(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="_2004年巴菲特致股东信核心总结" tabindex="-1">2004年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2004年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2004年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净资产增长83亿美元，每股账面价值增长10.5%</li><li>落后标普500指数0.4个百分点</li><li>40年复合增长率21.9%</li></ul><h2 id="主要投资决策" tabindex="-1">主要投资决策 <a class="header-anchor" href="#主要投资决策" aria-label="Permalink to &quot;主要投资决策&quot;">​</a></h2><h3 id="重大收购" tabindex="-1">重大收购 <a class="header-anchor" href="#重大收购" aria-label="Permalink to &quot;重大收购&quot;">​</a></h3><ul><li><strong>无重大收购完成</strong>：寻找大象级收购目标未果</li><li>年底持有430亿美元现金等价物，&quot;不是令人愉快的处境&quot;</li></ul><h3 id="投资组合变化" tabindex="-1">投资组合变化 <a class="header-anchor" href="#投资组合变化" aria-label="Permalink to &quot;投资组合变化&quot;">​</a></h3><ul><li>外汇合约增至214亿美元，分布在12种货币</li><li>继续减持垃圾债券</li><li>增持富国银行，新建仓安海斯-布希和沃尔玛</li></ul><h2 id="关键理念" tabindex="-1">关键理念 <a class="header-anchor" href="#关键理念" aria-label="Permalink to &quot;关键理念&quot;">​</a></h2><h3 id="投资哲学" tabindex="-1">投资哲学 <a class="header-anchor" href="#投资哲学" aria-label="Permalink to &quot;投资哲学&quot;">​</a></h3><ul><li>&quot;我们将持仓视为企业的部分所有权&quot;——这是自19岁以来的投资基石</li><li>四大持仓（运通、可口可乐、吉列、富国银行）加权持有12.5年，年化回报令人满意</li></ul><h3 id="衍生品风险警示" tabindex="-1">衍生品风险警示 <a class="header-anchor" href="#衍生品风险警示" aria-label="Permalink to &quot;衍生品风险警示&quot;">​</a></h3><ul><li>Gen Re证券业务清盘持续亏损</li><li>警告衍生品交易的系统性风险</li><li>&quot;一个巨大薪酬从假定数字中流出的业务显然充满危险&quot;</li></ul><h3 id="美国贸易赤字" tabindex="-1">美国贸易赤字 <a class="header-anchor" href="#美国贸易赤字" aria-label="Permalink to &quot;美国贸易赤字&quot;">​</a></h3><ul><li>经常账户赤字6180亿美元，每天输送18亿美元财富给世界</li><li>预测美元将继续贬值</li><li>批评贸易政策导致&quot;佃农社会&quot;倾向</li></ul><h2 id="业绩衡量" tabindex="-1">业绩衡量 <a class="header-anchor" href="#业绩衡量" aria-label="Permalink to &quot;业绩衡量&quot;">​</a></h2><h3 id="两个核心指标" tabindex="-1">两个核心指标 <a class="header-anchor" href="#两个核心指标" aria-label="Permalink to &quot;两个核心指标&quot;">​</a></h3><ol><li><strong>每股投资额</strong>：80,636美元（2006年数据），复合增长27.5%</li><li><strong>每股非保险业务收益</strong>：税前3,625美元，复合增长31.7%</li></ol><h3 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h3><ul><li>浮存金461亿美元，成本接近零</li><li>GEICO市场份额增长，广告支出增至5.02亿美元</li></ul><h2 id="管理理念" tabindex="-1">管理理念 <a class="header-anchor" href="#管理理念" aria-label="Permalink to &quot;管理理念&quot;">​</a></h2><h3 id="分权管理" tabindex="-1">分权管理 <a class="header-anchor" href="#分权管理" aria-label="Permalink to &quot;分权管理&quot;">​</a></h3><ul><li>查理和巴菲特的角色：加油打气、塑造文化、资本配置</li><li>管理者通过努力有效的工作回报信任</li></ul><h3 id="继任计划" tabindex="-1">继任计划 <a class="header-anchor" href="#继任计划" aria-label="Permalink to &quot;继任计划&quot;">​</a></h3><ul><li>三位内部CEO候选人已确定</li><li>投资继任人问题需要解决（Lou Simpson只比巴菲特小6岁）</li></ul><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><blockquote><p>&quot;投资者应该记住，兴奋和费用是他们的敌人。如果他们坚持要择时参与股市，应该在别人贪婪时恐惧，在别人恐惧时贪婪。&quot;</p></blockquote><blockquote><p>&quot;如果你不知道某人站在哪一边，他可能不是站在你这一边。&quot;</p></blockquote><hr><p><em>生成日期：2026年4月</em></p>',30)])])}const b=l(o,[["render",r]]);export{q as __pageData,b as default};
